const Dev = "ASSET_ID_START_MET_36";
const DI1_INVERT = false;
const DI2_INVERT = false;

const ID_DI1_STATE = 6101;
const ID_DI1_EVENT = 6102;
const ID_DI2_STATE = 8501;
const ID_DI2_EVENT = 10006;

const ID_DI1_LABEL = 6201;
const ID_DI2_LABEL = 10006;

const DEDUPE_WINDOW_MS = 3000;  

function toBool(v) { return !!v; }

function stateLabel(isHigh, invert) {
    const logical = invert ? !isHigh : isHigh;
    return logical ? "GESLOTEN" : "OPEN";
}

function decodeLT22222(bytes, fport) {
    if (!Buffer.isBuffer(bytes)) throw new Error("payload is not a Buffer");
    if (fport !== 2) throw new Error("Unexpected fport, expected 2 for I/O data");
    if (bytes.length < 11) throw new Error("payload too short for LT22222");

    const hardware = (bytes[10] & 0xC0) >> 6;
    const mode = (bytes[10] & 0x3F);

    const out = {
        hardware: hardware === 1 ? "LT22222" : "LT33222/unknown",
        mode,
        work_mode: mode === 6 ? "Trigger mode" : `Mode ${mode}`,
        raw_byte2: bytes[2]
    };

    if (mode === 6) {
        out.mode_status = toBool(bytes[9]);

        out.di2_status = toBool(bytes[2] & 0x08);
        out.di2_flag = toBool(bytes[2] & 0x04);
        out.di1_status = toBool(bytes[2] & 0x02);
        out.di1_flag = toBool(bytes[2] & 0x01);
    }

    return out;
}

let buf;
if (Buffer.isBuffer(msg.payload)) {
    buf = msg.payload;
} else if (typeof msg.payload === "string") {
    buf = Buffer.from(msg.payload, "base64");
} else {
    node.error("msg.payload must be base64 string or Buffer", msg);
    return null;
}

let decoded;
try {
    decoded = decodeLT22222(buf, msg.fport);
} catch (e) {
    node.error(e.message, msg);
    return null;
}
msg.decoded = decoded;

if (decoded.mode !== 6) {
    return null;
}

const hasTriggerFlag = decoded.di1_flag || decoded.di2_flag;
if (!hasTriggerFlag) {
    return null;
}

const now = Date.now();
const payloadB64 = Buffer.from(buf).toString("base64");

const last = context.get("lastEvent") || {
    payload: null,
    ts: 0
};

if (last.payload === payloadB64 && (now - last.ts) < DEDUPE_WINDOW_MS) {
    return null;
}

context.set("lastEvent", {
    payload: payloadB64,
    ts: now
});

const mid = global.get("mid") || 0;
const TS = msg.time ? new Date(msg.time).toISOString() : new Date().toISOString();

const result = {
    MID: mid,
    D: [{
        Dev,
        TS,
        ED: [],
        MD: []
    }]
};

const di1State = decoded.di1_status;
const di2State = decoded.di2_status;

//result.D[0].MD.push({ Id: ID_DI1_STATE, Val: di1State ? 1 : 0 });
//result.D[0].MD.push({ Id: ID_DI1_EVENT, Val: decoded.di1_flag ? 1 : 0 });

result.D[0].MD.push({ Id: ID_DI2_STATE, Val: di2State ? 1 : 0 });
//result.D[0].MD.push({ Id: ID_DI2_EVENT, Val: decoded.di2_flag ? 1 : 0 });

//result.D[0].ED.push({ Id: ID_DI1_LABEL, V: stateLabel(di1State, DI1_INVERT) });
result.D[0].ED.push({ Id: ID_DI2_LABEL, Val: stateLabel(di2State, DI2_INVERT) });

if (msg.snr !== undefined) result.D[0].MD.push({ Id: 5400, Val: Number(msg.snr) });
if (msg.rssi !== undefined) result.D[0].MD.push({ Id: 5500, Val: Number(msg.rssi) });
if (msg.dr && msg.dr.spreadFactor !== undefined) {
    result.D[0].MD.push({ Id: 5200, Val: Number(msg.dr.spreadFactor) });
}

global.set("mid", mid + 1);
msg.payload = result;
return msg;
